import json
import urllib.request
import re

def generate_valid_syllables():
    # A list of valid syllables without tones
    url = "https://raw.githubusercontent.com/mozillazg/pinyin-data/master/pinyin.txt"
    req = urllib.request.Request(url)
    try:
        html = urllib.request.urlopen(req).read().decode('utf-8')
    except Exception as e:
        print(f"Failed to fetch pinyin: {e}")
        return set()

    syllables = set()
    for line in html.split('\n'):
        if line.startswith('#') or not line:
            continue
        # Format is U+XXXX: pin1 yin1 # char
        parts = line.split(':')
        if len(parts) > 1:
            pys = parts[1].split('#')[0].strip().split(',')
            for py in pys:
                py = py.strip()
                # remove tone digits
                py = re.sub(r'\d+', '', py)
                syllables.add(py)
    return syllables

def get_xh_code(py, xh):
    if len(py) == 1:
        return py + py
    zero_initials = ['ai', 'an', 'ang', 'ao', 'ei', 'en', 'eng', 'er', 'ou']
    if py in zero_initials:
        return py[0] + xh['yunmu'].get(py, '')

    # special check for "ng", "m" alone etc. (rare, ignore or map?)
    if py in ['ng', 'hm', 'hng', 'm', 'n']:
        return None

    # standard
    for sm in ['zh', 'ch', 'sh', 'b', 'p', 'm', 'f', 'd', 't', 'n', 'l', 'g', 'k', 'h', 'j', 'q', 'x', 'r', 'z', 'c', 's', 'y', 'w']:
        if py.startswith(sm):
            ym = py[len(sm):]
            if not ym:
                # sometimes 'zhi' is just 'zh'? 
                return None

            # handle ü -> u for j, q, x, y
            if sm in ['j', 'q', 'x', 'y']:
                if ym == 'u':
                    ym = 'v'
                elif ym == 'ue':
                    ym = 've'
                elif ym == 'un':
                    ym = 'vn'
                elif ym == 'uan':
                    ym = 'van'

            if ym in xh['yunmu']:
                return xh['shengmu'][sm] + xh['yunmu'][ym]

            # Try to see if there is v/ve mappings
            # Wait, 'vn' -> 'un' key? 'van' -> 'uan' key?
            if ym == 'vn':
                if 'vn' in xh['yunmu']:
                    return xh['shengmu'][sm] + xh['yunmu']['vn']
                elif 'un' in xh['yunmu']:
                    return xh['shengmu'][sm] + xh['yunmu']['un']
            if ym == 'van':
                if 'van' in xh['yunmu']:
                    return xh['shengmu'][sm] + xh['yunmu']['van']
                elif 'uan' in xh['yunmu']:
                    return xh['shengmu'][sm] + xh['yunmu']['uan']

            break

    return None

def main():
    with open('context/xiaohe.json') as f:
        xh = json.load(f)

    syllables = generate_valid_syllables()
    print(f"Found {len(syllables)} unique pinyin syllables.")

    valid_xh_codes = set()
    for py in syllables:
        code = get_xh_code(py, xh)
        if code:
            valid_xh_codes.add(code)
        else:
            print(f"Could not map: {py}")

    print(f"Found {len(valid_xh_codes)} valid xiaohe codes.")
    with open('valid_codes.json', 'w') as f:
        json.dump(list(valid_xh_codes), f)

